DROP TABLE IF EXISTS `member_status_histories`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `member_status_histories` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `member_id` bigint(20) unsigned DEFAULT NULL,
  `corporate_member_id` bigint(20) unsigned DEFAULT NULL,
  `status` enum('active','suspended','cancelled','absent','extended','expired','pause') DEFAULT NULL,
  `reason` varchar(255) DEFAULT NULL,
  `changed_by` bigint(20) unsigned DEFAULT NULL,
  `changed_at` timestamp NULL DEFAULT NULL,
  `start_date` date NOT NULL,
  `end_date` date DEFAULT NULL,
  `used_up_to` date DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `created_by` bigint(20) DEFAULT NULL,
  `updated_by` bigint(20) DEFAULT NULL,
  `deleted_by` bigint(20) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `member_status_histories_member_id_foreign` (`member_id`),
  KEY `member_status_histories_changed_by_foreign` (`changed_by`),
  KEY `member_status_histories_corporate_member_id_foreign` (`corporate_member_id`),
  CONSTRAINT `member_status_histories_changed_by_foreign` FOREIGN KEY (`changed_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `member_status_histories_corporate_member_id_foreign` FOREIGN KEY (`corporate_member_id`) REFERENCES `corporate_members` (`id`) ON DELETE CASCADE,
  CONSTRAINT `member_status_histories_member_id_foreign` FOREIGN KEY (`member_id`) REFERENCES `members` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=16827 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
